class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def append(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
            return
        last = self.head
        while last.next:
            last = last.next
        last.next = new_node

    def sublist_search(self, pattern_list):
        """
        Ana bağlı listede (self) bir alt liste (pattern_list) olup olmadığını arar.
        """
        # Kenar durum: Boş bir desen her zaman herhangi bir listenin alt listesi olarak kabul edilir.
        if not pattern_list.head:
            return True

        # Kenar durum: Ana liste boşsa ve desen boş değilse, alt liste bulunamaz.
        if not self.head:
            return False

        current_main = self.head

        # Ana listeyi dolaşır
        while current_main:
            temp_main = current_main
            temp_pattern = pattern_list.head

            # İç döngü: desenin mevcut konumdan eşleşip eşleşmediğini kontrol eder
            while temp_main and temp_pattern and temp_main.data == temp_pattern.data:
                temp_main = temp_main.next
                temp_pattern = temp_pattern.next

            # Eğer temp_pattern sona erdiyse, desenin tamamı ana listede bulunmuştur.
            if not temp_pattern:
                return True

            # Ana listedeki bir sonraki düğüme geç
            current_main = current_main.next

        # Döngü bitti ve desen bulunamadıysa
        return False
